def first_positive(nums):
    for n in nums:
        if n > 0:
            return n
    return None

print(first_positive([-1, 0, 4, 9]))
print(first_positive([-2, -3]))

def scan(rows):
    for r in rows:
        if r.get("status") == "fatal":
            break
        if not r.get("id"):
            continue
        print(r["id"])

scan([
    {"id": "", "status": "ok"},
    {"id": "C001", "status": "ok"},
    {"id": "C002", "status": "fatal"},
    {"id": "C003", "status": "ok"},
])

