# un solo pase O(n) en lugar de re-escanear por cada métrica
decisiones = ["accept", "reject", "review", "reject"]
n_total = n_accept = n_reject = n_review = 0
for d in decisiones:
    n_total += 1
    if d == "accept":
        n_accept += 1
    elif d == "reject":
        n_reject += 1
    elif d == "review":
        n_review += 1
print({"n_total": n_total, "n_accept": n_accept, "n_reject": n_reject, "n_review": n_review})

